import{_ as i,o as a,c as o,ag as r}from"./chunks/framework.DTiDeF2Q.js";const m=JSON.parse('{"title":"Aliasuri Chmod | Dotfiles (RO)","titleTemplate":":title","description":"Comenzi scurte pentru permisiuni. Prezentare generală pentru Dotfiles v0.2.495. Compatibil cu macOS, Linux și WSL prin Dotfiles.","frontmatter":{"title":"Aliasuri Chmod | Dotfiles","description":"Comenzi scurte pentru permisiuni. Prezentare generală pentru Dotfiles v0.2.495. Compatibil cu macOS, Linux și WSL prin Dotfiles.","lang":"ro-RO","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Aliasuri Chmod | Previzualizare Dotfiles","canonical":"/ro/aliases/chmod/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Aliasuri Chmod","pageType":"docs","schemaType":"WebPage","permalink":"/ro/aliases/chmod/"},"headers":[],"relativePath":"ro/aliases/chmod/index.md","filePath":"ro/aliases/chmod/index.md","lastUpdated":1773010926000}'),t={name:"ro/aliases/chmod/index.md"};function c(l,e,d,n,s,p){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="aliasuri-chmod" tabindex="-1">Aliasuri Chmod <a class="header-anchor" href="#aliasuri-chmod" aria-label="Permalink to &quot;Aliasuri Chmod&quot;">​</a></h1><p>Comenzi scurte pentru permisiuni.</p><p>Această pagină prezintă un grup de aliasuri și scurtăturile sale de comandă obișnuite. Citiți-o mai întâi pentru a înțelege convențiile de denumire, intrările așteptate și tiparele de execuție sigure. Apoi deschideți anexa de referință pentru inventarul complet de comenzi și sintaxa exactă. Aceste aliasuri reduc tastarea repetitivă și mențin un comportament consistent pe macOS, Linux și WSL.</p><h2 id="cand-se-utilizeaza" tabindex="-1">Când se utilizează <a class="header-anchor" href="#cand-se-utilizeaza" aria-label="Permalink to &quot;Când se utilizează&quot;">​</a></h2><p>Utilizați această pagină înainte de lucrul zilnic în shell când aveți nevoie de tipare de comandă previzibile.</p><h2 id="ce-este-inclus" tabindex="-1">Ce este inclus <a class="header-anchor" href="#ce-este-inclus" aria-label="Permalink to &quot;Ce este inclus&quot;">​</a></h2><ul><li>Aliasuri: 17</li><li>Funcții helper: 0</li><li>Fișiere sursă: 1</li></ul><h2 id="exemple-rapide" tabindex="-1">Exemple rapide <a class="header-anchor" href="#exemple-rapide" aria-label="Permalink to &quot;Exemple rapide&quot;">​</a></h2><ul><li><code>chmod_000</code> → <code>change_permission 000</code></li><li><code>chmod_1755</code> → <code>&#39;change_permission 1755&#39; # Sticky bit + 755</code></li><li><code>chmod_2755</code> → <code>&#39;change_permission 2755&#39; # Setgid + 755</code></li><li><code>chmod_400</code> → <code>&#39;change_permission 400&#39; # Doar citire pentru proprietar</code></li><li><code>chmod_444</code> → <code>&#39;change_permission 444&#39; # Doar citire pentru toți</code></li><li><code>chmod_4755</code> → <code>&#39;change_permission 4755&#39; # Setuid + 755</code></li><li><code>chmod_600</code> → <code>&#39;change_permission 600&#39; # Citire/scriere pentru proprietar</code></li><li><code>chmod_644</code> → <code>&#39;change_permission 644&#39; # Citire/scriere proprietar, citire alții</code></li><li><code>chmod_664</code> → <code>&#39;change_permission 664&#39; # Citire/scriere proprietar și grup, citire alții</code></li><li><code>chmod_666</code> → <code>&#39;change_permission 666&#39; # Citire/scriere pentru toți</code></li><li><code>chmod_700</code> → <code>&#39;change_permission 700&#39; # Acces complet doar proprietar</code></li><li><code>chmod_744</code> → <code>&#39;change_permission 744&#39; # Complet proprietar, citire alții</code></li></ul><h2 id="pasul-urmator" tabindex="-1">Pasul următor <a class="header-anchor" href="#pasul-urmator" aria-label="Permalink to &quot;Pasul următor&quot;">​</a></h2><p>Deschideți lista completă:</p>',11)])])}const h=i(t,[["render",c]]);export{m as __pageData,h as default};
